trend.sqlSketch:
SELECT segment, year, level,
       structural_break(level) OVER (PARTITION BY segment ORDER BY year) AS bp
FROM v_segment_panel;

comparison_pair.sqlSketch:
SELECT a.metric, a.value AS cohort_a, b.value AS cohort_b
FROM v_cohort_panel a JOIN v_cohort_panel b USING (metric, age)
WHERE a.cohort = $1 AND b.cohort = $2;
